import json, sys

# dotnet list package --format json outputs multiple JSON objects concatenated
# Parse them individually
def parse_packages(filename):
    with open(filename) as f:
        content = f.read()
    # Split by '}{' to handle multiple JSON objects
    parts = content.replace('}\n{', '}|||{').split('|||')
    result = {}
    for part in parts:
        data = json.loads(part)
        for proj in data.get('projects', []):
            proj_name = proj['path'].split('/')[-1]
            for fw in proj.get('frameworks', []):
                for pkg in fw.get('topLevelPackages', []):
                    key = (proj_name, pkg['id'])
                    result[key] = (pkg.get('requestedVersion',''), pkg.get('resolvedVersion',''))
    return result

baseline = parse_packages('baseline-packages.json')
after = parse_packages('after-cpm-packages.json')

all_keys = sorted(set(baseline.keys()) | set(after.keys()))
changes = []
unchanged = []
for k in all_keys:
    b = baseline.get(k)
    a = after.get(k)
    proj, pkg = k
    if b and a:
        if b[1] != a[1]:
            changes.append((proj, pkg, b[0], b[1], a[0], a[1]))
        else:
            unchanged.append((proj, pkg, b[1], a[1]))
    elif b and not a:
        changes.append((proj, pkg, b[0], b[1], '-', '-'))
    elif a and not b:
        changes.append((proj, pkg, '-', '-', a[0], a[1]))

print('=== CHANGES ===')
for c in changes:
    print(f'{c[0]:20} {c[1]:40} {c[2]:10}->{c[4]:10} (resolved: {c[3]:10}->{c[5]})')
print()
print('=== UNCHANGED ===')
for u in unchanged:
    print(f'{u[0]:20} {u[1]:40} {u[2]}')
